// Project-level architecture CANON: the cross-cutting standing decisions the
// FIRST service-backed feature establishes (its NFR posture, the AC layers the
// project uses, and the persistence-invariant patterns it applies), persisted
// under .tdd/architecture/canon.json so a LATER feature's per-story architect
// step can be PROJECTED deterministically instead of re-run as a live agent turn.
//
// This is the cross-cutting sibling of architecture-conventions.ts. Where
// conventions.json pins the role -> module LAYOUT (and the layering gate hard-
// conforms it), canon.json captures the rules the architect otherwise restates on
// every story: which NFRs stand project-wide, which AC layers are in play, and
// which invariant classes the schema uses. A story whose ACs all map onto the
// canon needs no architect turn (projectArchitecturalNotes writes their notes
// deterministically); a story that introduces something the canon has not seen is
// NOVEL (architectNovelty), and only then is the architect pulled in to clean the
// AC + amend the canon (via the revise-routing self-heal).
//
// Like conventions.json, canon.json is a DETERMINISTIC projection of the feature's
// architecture.json + its ACs (written by code, not an LLM), so it cannot drift
// from the contracts the design gate already reads.

import { existsSync, readFileSync, writeFileSync, mkdirSync, readdirSync } from "fs";
import { dirname } from "path";
import { architectureCanonJson, architectureJson, storiesDir, storyAcIds, readAcLayer, acJson } from "./sftdd-paths.js";

/** One standing NFR: category + the requirement text (the project's posture). */
export interface CanonNfr {
  category: string;
  requirement: string;
}

/** One persistence-invariant pattern the project uses: its type + a representative
 *  one-line brief (the first instance that established it). */
export interface CanonInvariant {
  type: string;
  brief: string;
}

/** The project's persisted architecture canon. */
export interface ArchitectureCanon {
  /** The feature whose architecture first established the canon. */
  established_by: string;
  established_at: string;
  /** The AC layers (API | E2E | Infra) the project uses. A story AC whose layer
   *  is absent here is novel (a new kind of surface the canon has not classified). */
  ac_layers: string[];
  /** The standing NFR posture (category + requirement), deduped. */
  nfr_posture: CanonNfr[];
  /** The persistence-invariant patterns in use (one per type), deduped by type. */
  invariant_patterns: CanonInvariant[];
}

interface ArchitectureNfr {
  category?: string;
  requirement?: string;
}
interface ArchitectureInvariant {
  type?: string;
  brief?: string;
}
interface ArchitectureDoc {
  service_backed?: boolean;
  nfrs?: ArchitectureNfr[];
  persistence_invariants?: ArchitectureInvariant[];
}

/** Minimal AC view the canon reasons over (the layer it exercises). */
export interface CanonAc {
  layer?: string;
}

function uniq(xs: string[]): string[] {
  return [...new Set(xs.filter((x) => typeof x === "string" && x.length > 0))];
}

// --- Read -------------------------------------------------------------------

/** Read the persisted canon, or undefined when none is established yet. */
export function readCanon(sftddDir: string): ArchitectureCanon | undefined {
  const f = architectureCanonJson(sftddDir);
  if (!existsSync(f)) return undefined;
  try {
    return JSON.parse(readFileSync(f, "utf8")) as ArchitectureCanon;
  } catch {
    return undefined;
  }
}

/** True once the project canon is on disk (the project/skip probe). */
export function canonReady(sftddDir: string): boolean {
  return existsSync(architectureCanonJson(sftddDir));
}

// --- Derive -----------------------------------------------------------------

/**
 * Project the persistable canon from a feature's architecture.json + its ACs.
 * Returns undefined when the feature is NOT service-backed (a trivial feature
 * establishes no standing architecture). `established_by` is the feature id; `now`
 * is injectable for deterministic tests. `acLayers` are the AC.layer values across
 * the feature's stories (the caller collects them from disk).
 */
export function deriveCanon(
  architectureJsonContent: string,
  acLayers: string[],
  featureId: string,
  now: () => Date = () => new Date(),
): ArchitectureCanon | undefined {
  let doc: ArchitectureDoc;
  try {
    doc = JSON.parse(architectureJsonContent) as ArchitectureDoc;
  } catch {
    return undefined;
  }
  if (doc.service_backed !== true) return undefined;

  const nfr_posture: CanonNfr[] = [];
  const seenNfr = new Set<string>();
  for (const n of doc.nfrs ?? []) {
    if (typeof n.category !== "string" || typeof n.requirement !== "string") continue;
    const key = `${n.category}�${n.requirement}`;
    if (seenNfr.has(key)) continue;
    seenNfr.add(key);
    nfr_posture.push({ category: n.category, requirement: n.requirement });
  }

  const invariant_patterns: CanonInvariant[] = [];
  const seenInv = new Set<string>();
  for (const p of doc.persistence_invariants ?? []) {
    if (typeof p.type !== "string") continue;
    if (seenInv.has(p.type)) continue; // one representative per type
    seenInv.add(p.type);
    invariant_patterns.push({ type: p.type, brief: typeof p.brief === "string" ? p.brief : "" });
  }

  return {
    established_by: featureId,
    established_at: now().toISOString(),
    ac_layers: uniq(acLayers),
    nfr_posture,
    invariant_patterns,
  };
}

// --- Establish (idempotent) -------------------------------------------------

export interface EstablishCanonResult {
  /** A new canon.json was written this call. */
  established: boolean;
  /** The canon now on disk (whether just established or pre-existing). */
  canon?: ArchitectureCanon;
}

/**
 * Establish the project canon from a feature's architecture.json + ACs IF none
 * exists yet. Idempotent + deterministic: a no-op once canon.json is on disk
 * (later features inherit + amend, never overwrite), and a no-op when the feature
 * is not service-backed (nothing standing to pin). The FIRST service-backed
 * feature's cross-cutting decisions become the project canon.
 */
export function establishCanonIfAbsent(
  sftddDir: string,
  featureId: string,
  architectureJsonContent: string,
  acLayers: string[],
  now: () => Date = () => new Date(),
): EstablishCanonResult {
  const existing = readCanon(sftddDir);
  if (existing) return { established: false, canon: existing };

  const canon = deriveCanon(architectureJsonContent, acLayers, featureId, now);
  if (!canon) return { established: false };

  writeCanon(sftddDir, canon);
  return { established: true, canon };
}

/** Collect the distinct AC layers declared across a feature's stories (disk
 *  truth), for deriving the canon's ac_layers. */
export function featureAcLayers(sftddDir: string, featureId: string): string[] {
  const stories = storiesDir(sftddDir, featureId);
  if (!existsSync(stories)) return [];
  const layers: string[] = [];
  for (const s of readdirSync(stories)) {
    for (const acId of storyAcIds(sftddDir, featureId, s)) {
      const l = readAcLayer(sftddDir, featureId, acId);
      if (l) layers.push(l);
    }
  }
  return uniq(layers);
}

/**
 * Disk-reading wrapper over establishCanonIfAbsent: read the feature's
 * architecture.json + collect its AC layers, then establish the canon if absent.
 * The thin I/O seam the reconcile step calls (mirrors establishConventionsIfAbsent,
 * which also reads from disk). A no-op when architecture.json is missing.
 */
export function establishCanonFromDisk(
  sftddDir: string,
  featureId: string,
  now: () => Date = () => new Date(),
): EstablishCanonResult {
  if (readCanon(sftddDir)) return { established: false, canon: readCanon(sftddDir) };
  const archFile = architectureJson(sftddDir, featureId);
  if (!existsSync(archFile)) return { established: false };
  let content: string;
  try {
    content = readFileSync(archFile, "utf8");
  } catch {
    return { established: false };
  }
  return establishCanonIfAbsent(sftddDir, featureId, content, featureAcLayers(sftddDir, featureId), now);
}

/**
 * Disk-reading coverage verdict for a story: read the canon, the story's AC
 * layers, and the feature architecture.json, then assert the canon covers them.
 * The projection CLI calls this , OK projects the notes, a gap raises the
 * architect-canon-gap smell (routing to the architect). `{ ok: true }` when no
 * canon exists yet (nothing to conform to; the architect path handles it).
 */
export function evaluateStoryCanon(sftddDir: string, featureId: string, story: string): CanonCoverage {
  const canon = readCanon(sftddDir);
  if (!canon) return { ok: true };
  // The feature that ESTABLISHED the canon is its source, not a conformer: its
  // own stories + evolving architecture.json ARE the canon, so never gap-check a
  // feature against the canon it created (that self-thrash routed F1's own later
  // stories through the architect). Only LATER features conform.
  if (canon.established_by === featureId) return { ok: true };
  const layers: CanonAc[] = storyAcIds(sftddDir, featureId, story).map((ac) => ({
    layer: readAcLayer(sftddDir, featureId, ac) ?? undefined,
  }));
  const archFile = architectureJson(sftddDir, featureId);
  let archContent: string | undefined;
  if (existsSync(archFile)) {
    try {
      archContent = readFileSync(archFile, "utf8");
    } catch {
      archContent = undefined;
    }
  }
  return assertCanonCoverage(canon, layers, archContent);
}

/** Persist a canon (used by establish + amend). */
export function writeCanon(sftddDir: string, canon: ArchitectureCanon): void {
  const out = architectureCanonJson(sftddDir);
  mkdirSync(dirname(out), { recursive: true });
  writeFileSync(out, JSON.stringify(canon, null, 2) + "\n");
}

// --- Amend (extend the canon from a novelty turn) ---------------------------

export interface CanonAmendment {
  ac_layers?: string[];
  nfr_posture?: CanonNfr[];
  invariant_patterns?: CanonInvariant[];
}

/**
 * Merge new standing rules into the canon (deduped), returning the updated canon.
 * Used when a novelty turn's architect output introduces a new AC layer, NFR, or
 * invariant pattern: the canon grows so the NEXT feature inherits the new rule.
 * `established_by`/`established_at` are preserved (the canon's origin is stable).
 */
export function amendCanon(canon: ArchitectureCanon, add: CanonAmendment): ArchitectureCanon {
  const nfrKey = (n: CanonNfr) => `${n.category}�${n.requirement}`;
  const nfrSeen = new Set(canon.nfr_posture.map(nfrKey));
  const nfr_posture = [...canon.nfr_posture];
  for (const n of add.nfr_posture ?? []) {
    if (typeof n.category !== "string" || typeof n.requirement !== "string") continue;
    if (nfrSeen.has(nfrKey(n))) continue;
    nfrSeen.add(nfrKey(n));
    nfr_posture.push({ category: n.category, requirement: n.requirement });
  }

  const invSeen = new Set(canon.invariant_patterns.map((p) => p.type));
  const invariant_patterns = [...canon.invariant_patterns];
  for (const p of add.invariant_patterns ?? []) {
    if (typeof p.type !== "string") continue;
    if (invSeen.has(p.type)) continue;
    invSeen.add(p.type);
    invariant_patterns.push({ type: p.type, brief: typeof p.brief === "string" ? p.brief : "" });
  }

  return {
    ...canon,
    ac_layers: uniq([...canon.ac_layers, ...(add.ac_layers ?? [])]),
    nfr_posture,
    invariant_patterns,
  };
}

// --- Novelty (project-or-dispatch decision) ---------------------------------

export interface NoveltyResult {
  /** True when the story introduces something the canon has not seen, so a live
   *  architect turn is warranted (to clean the AC + amend the canon). */
  novel: boolean;
  /** Human-readable reasons (for the agent-log + the architect's handoff brief). */
  reasons: string[];
}

/**
 * Decide whether a story is NOVEL against the canon: any AC exercising a layer the
 * canon has not classified, or (from the story's architecture.json, when present)
 * a persistence-invariant type or an NFR category the canon does not yet carry.
 * Pure, deterministic. A story that is NOT novel can have its per-AC
 * architectural_notes projected from the canon with no architect turn.
 *
 * FAIL-TOWARD-PROJECTION: this reports novelty only on a CONCRETE new dimension; a
 * borderline story that maps onto the canon is treated as not-novel and projected.
 * The design gate + build-lane layering/fitness gates remain the backstop, and a
 * projected AC that turns out mis-placed self-heals by routing to the architect
 * (the architect-canon-gap smell) rather than an up-front live turn.
 */
export function architectNovelty(
  canon: ArchitectureCanon,
  storyAcs: CanonAc[],
  storyArchitectureJsonContent?: string,
): NoveltyResult {
  const reasons: string[] = [];

  const knownLayers = new Set(canon.ac_layers);
  const unknownLayers = uniq(
    storyAcs.map((a) => a.layer).filter((l): l is string => typeof l === "string" && !knownLayers.has(l)),
  );
  for (const l of unknownLayers) {
    reasons.push(`AC layer "${l}" is not in the project canon (${canon.ac_layers.join(", ") || "none"})`);
  }

  if (storyArchitectureJsonContent) {
    let doc: ArchitectureDoc | undefined;
    try {
      doc = JSON.parse(storyArchitectureJsonContent) as ArchitectureDoc;
    } catch {
      doc = undefined;
    }
    if (doc) {
      const knownInv = new Set(canon.invariant_patterns.map((p) => p.type));
      for (const t of uniq((doc.persistence_invariants ?? []).map((p) => p.type ?? ""))) {
        if (!knownInv.has(t)) reasons.push(`persistence-invariant type "${t}" is not a canon pattern`);
      }
      const knownCat = new Set(canon.nfr_posture.map((n) => n.category));
      for (const c of uniq((doc.nfrs ?? []).map((n) => n.category ?? ""))) {
        if (!knownCat.has(c)) reasons.push(`NFR category "${c}" is not in the canon posture`);
      }
    }
  }

  return { novel: reasons.length > 0, reasons };
}

// --- Coverage verdict (the design-gate recognizer) --------------------------

export type CanonCoverage = { ok: true } | { ok: false; gaps: string[] };

/**
 * Gate-style verdict: does the canon COVER this story (its AC layers + the
 * feature architecture.json's invariant/NFR dimensions)? A gap means the story
 * introduces something the canon has not seen, so a deterministic projection
 * would be guessing , the story must go to the architect (to annotate it properly
 * AND amend the canon). The reactive half of the project-or-dispatch model: the
 * projection step calls this and, on a gap, raises the `architect-canon-gap` smell
 * (routed to the architect via revise-routing) instead of writing a blind note.
 */
export function assertCanonCoverage(
  canon: ArchitectureCanon,
  storyAcs: CanonAc[],
  storyArchitectureJsonContent?: string,
): CanonCoverage {
  const nv = architectNovelty(canon, storyAcs, storyArchitectureJsonContent);
  return nv.novel ? { ok: false, gaps: nv.reasons } : { ok: true };
}

// --- Project (deterministic per-AC architectural_notes) ---------------------

/**
 * Deterministically compose an AC's `architectural_notes` from the canon, for the
 * common (non-novel) case where the AC maps cleanly. Names the layer the AC
 * exercises, the standing posture it inherits, and that the canon (not a live
 * architect turn) placed it, so the note is honest about its provenance. Returns
 * undefined when the AC has no layer to anchor on (nothing to project).
 */
export function projectArchitecturalNotes(canon: ArchitectureCanon, ac: CanonAc): string | undefined {
  if (typeof ac.layer !== "string" || ac.layer.length === 0) return undefined;
  const posture = canon.nfr_posture.map((n) => n.category);
  const postureStr = posture.length ? ` Inherits the project NFR posture (${uniq(posture).join(", ")}).` : "";
  return (
    `Layer ${ac.layer}, placed per the project architecture canon established by ${canon.established_by}.` +
    postureStr +
    ` Projected deterministically (no novel cross-cutting concern); the design gate + layering fitness are the backstop.`
  );
}

// --- Disk writer (the deterministic project-architect-notes effect) ---------

/**
 * Write each of a story's ACs a projected `architectural_notes` from the canon,
 * for the common (non-novel) case, so the design lane advances with NO architect
 * turn. Idempotent: an AC that already carries notes is left untouched (never
 * clobbers a live architect's annotation). Returns the number of ACs annotated.
 * A no-op (returns 0) when no canon is established or the story has no ACs.
 */
export function projectStoryNotes(sftddDir: string, featureId: string, story: string): number {
  const canon = readCanon(sftddDir);
  if (!canon) return 0;
  let annotated = 0;
  for (const acId of storyAcIds(sftddDir, featureId, story)) {
    const file = acJson(sftddDir, featureId, story, acId);
    if (!existsSync(file)) continue;
    let ac: Record<string, unknown>;
    try {
      ac = JSON.parse(readFileSync(file, "utf8")) as Record<string, unknown>;
    } catch {
      continue;
    }
    if (typeof ac.architectural_notes === "string" && ac.architectural_notes.trim().length > 0) continue;
    const note = projectArchitecturalNotes(canon, { layer: typeof ac.layer === "string" ? ac.layer : undefined });
    if (!note) continue;
    ac.architectural_notes = note;
    writeFileSync(file, JSON.stringify(ac, null, 2) + "\n");
    annotated++;
  }
  return annotated;
}
